import {
  Button,
  Container,
  Divider,
  Fab,
  Grid,
  Link,
  Box,
  useScrollTrigger,
  Zoom,
} from "@mui/material";
import React from "react";
import Introduction from "./Introduction";
import ProjectSlides from "./ProjectSlides";
import KeyboardArrowUpIcon from "@mui/icons-material/KeyboardArrowUp";

import aboutMeIntroductionData from "../../jsData/aboutMeData";
import typeTwoIntroData from "../../jsData/typetwoData";
import gisIntroData from "../../jsData/gisData";
import Projects from "../projects/Projects";
import Skills from "../skills/Skills";
import About from "../about/About";
import ContactMe from "../contact-me/ContactMe";
import Education from "../education/Education";

function ScrollTop(props) {
  const { children, window } = props;
  // Note that you normally won't need to set the window ref as useScrollTrigger
  // will default to window.
  // This is only being set here because the demo is in an iframe.
  const trigger = useScrollTrigger({
    target: window ? window() : undefined,
    disableHysteresis: true,
    threshold: 100,
  });

  const handleClick = (event) => {
    const anchor = (event.target.ownerDocument || document).querySelector(
      "#back-to-top-anchor"
    );

    if (anchor) {
      anchor.scrollIntoView({
        behavior: "smooth",
        block: "center",
      });
    }
  };
  return (
    <Zoom in={trigger}>
      <Box
        onClick={handleClick}
        role="presentation"
        sx={{ position: "fixed", bottom: 16, right: 16 }}
      >
        {children}
      </Box>
    </Zoom>
  );
}

function Home(props) {
  const projectsData = [typeTwoIntroData, gisIntroData];

  return (
    <div>
      <div id="back-to-top-anchor">
        <Introduction aboutMe={aboutMeIntroductionData} />
      </div>
      <br/>
      <br/>
      <div id="projects">
        <Projects />
      </div>
      <div id="skills">
        <Skills />
      </div>
      <div id="education">
        <Education />
      </div>
      <div id="contact-me">
        <ContactMe />
      </div>

      <ScrollTop {...props}>
        <Fab color="primary" size="small" aria-label="scroll back to top">
          <KeyboardArrowUpIcon />
        </Fab>
      </ScrollTop>
    </div>
  );
}

export default Home;
